export interface WorkflowDef {
    id: string;
    version: number;
    description?: string;
    nodes: NodeDef[];
    edges: EdgeDef[];
}
export interface NodeDef {
    id: string;
    prompt: string;
    loop?: LoopSpec;
    expects: ExpectsSpec;
}
export interface LoopSpec {
    over: string;
    alias: string;
    alsoEmitsItemId?: boolean;
    group?: string;
    head?: boolean;
}
export interface ExpectsSpec {
    success: {
        writes?: {
            state?: string[];
            artifact?: {
                pattern: string;
            };
        };
    };
    failure: {};
}
export interface EdgeDef {
    from: string;
    on: "success" | "failure" | "exhausted";
    to?: string;
    halt?: string;
    terminal?: "complete";
    advance?: "loop-or-next";
    next?: string;
    when?: string;
}
export interface RuntimeState {
    cursor: string;
    loopCursor: Record<string, number>;
    entryPrompt?: string;
    [key: string]: unknown;
}
export interface Event {
    eventId: string;
    nodeExecId: string;
    type: "started" | "progress" | "success" | "failure" | "workflow.started" | "workflow.completed" | "workflow.halted" | "node.dispatched" | "node.committed" | "node.remit-violation";
    ts: string;
    writes?: {
        state?: Record<string, unknown>;
        artifact?: {
            path: string;
            content: string;
        };
    };
    summary?: string;
    reason?: string;
    details?: string;
    workflowId?: string;
    instanceId?: string;
    violatedRule?: string;
}
